SELECT '项目统计' AS card_title, COUNT(*) AS total, SUM(CASE WHEN status = 1 THEN 1 ELSE 0 END) AS un_submit_ted, SUM(CASE WHEN status = 2 THEN 1 ELSE 0 END) AS in_progress, SUM(CASE WHEN status = 3 THEN 1 ELSE 0 END) AS completed FROM t_project_statis WHERE delete_flag = 0
and create_by = #{createBy}
